// Originally generated by ts-rs from the (now-removed) Rust desktop port.
// Frozen as a hand-maintained TS type since the Rust source is gone.

export type PlayerInfo = {
	// Stable per-player xml_id (Player.xmlId). Matches `player_id` on every
	// per-player array (player_history, units_produced, …) and
	// `player_roster[].player_index`. The unique key for joining/iterating
	// players, since `nation` collides in mirror matches (two players, same
	// nation). Added in PARSER_VERSION 2.6.0; optional so the frontend can
	// still read older blobs (which recover the id from player_roster).
	player_id?: number;
	player_name: string;
	nation: string | null;
	is_human: boolean;
	legitimacy: number | null;
	state_religion: string | null;
	difficulty: string | null;
	// The player's reigning leader at the end of the save — the last id in
	// their <Leaders> succession list, matching Player.leader(). Joins to
	// `characters[].xml_id`. Added in PARSER_VERSION 2.11.0; optional so the
	// frontend can still read older blobs. Null for a player who never had
	// a leader.
	leader_character_xml_id?: number | null;
};
